  select $_hc$[{"id":"artic-crazy-quilt-with-animals-181720","title":"'Crazy Quilt' with Animals","maker":"Florence Elizabeth Marvin","culture":"Brooklyn Heights","country":null,"region":null,"date_display":"1886","category":"textile","image_url":"https://www.artic.edu/iiif/2/20692004-784b-0c7b-9a15-0db2dd6e83e4/full/843,/0/default.jpg","source_name":"Art Institute of Chicago","source_url":"https://www.artic.edu/artworks/181720","license":"Public domain / Art Institute of Chicago","hook":"A worked surface where bird, cat, and deer motifs live in thread, pattern, and touch.","story":"'Crazy Quilt' with Animals is tied to Florence Elizabeth Marvin, Brooklyn Heights, 1886. Its interest is in accumulated decisions: color, pattern, edge, repair, and the time needed to make them cohere.","why_it_matters":"It makes patient labor visible without turning it into a footnote.","latitude":37.0902,"longitude":-95.7129,"week_key":"full-archive-2026-W01"},{"id":"artic-basket-35716","title":"Basket","maker":null,"culture":"England","country":null,"region":null,"date_display":"c. 1645","category":"textile","image_url":"https://www.artic.edu/iiif/2/8c7ef82e-1cb1-9dc5-ff8a-dab29259049b/full/843,/0/default.jpg","source_name":"Art Institute of Chicago","source_url":"https://www.artic.edu/artworks/35716","license":"Public domain / Art Institute of Chicago","hook":"A worked surface where crown, deer, and dog motifs live in thread, pattern, and touch.","story":"Basket is tied to England. The crown, deer, and dog motifs pull the eye in before the period label does.","why_it_matters":"It shows cloth as a serious historical surface, not decoration alone.","latitude":52.3555,"longitude":-1.1743,"week_key":"full-archive-2026-W01"},{"id":"artic-cabinet-or-box-depicting-scenes-from-the-old-testament-10503","title":"Cabinet or Box Depicting Scenes from the Old Testament","maker":"Rebecca Stonier Plaisted","culture":"England","country":null,"region":null,"date_display":"1668","category":"textile","